sql:
SELECT project_name, SUM(amount) as total_amount
FROM budget_outlays
GROUP BY project_name;

external_knowledge:
- 'born in a period of post-war economic boom' refers to departments established between 1950 and 2000;
- 'rapid growth' refers to a GDP growth rate greater than 2.5;
- 'an arm and a leg' refers to an amount exceeding 5 billion.

sql:
SELECT COUNT(*) AS number_of_increases
FROM budget_variations
WHERE variation_type = 'Increase' AND variation_status = 'approved';
